#include <stdio.h>
#include <math.h>

void DDA(int x1, int y1, int x2, int y2) {
 int dx = x2 - x1;
 int dy = y2 - y1;
 int steps;

 float x_inc, y_inc;
 float x = x1, y = y1;

 if (abs(dx) > abs(dy))
 steps = abs(dx);
 else
 steps = abs(dy);

 x_inc = (float)dx / steps;
 y_inc = (float)dy / steps;

 // Plot first pixel
 printf("(%.0f, %.0f)\n", round(x), round(y));

 for (int i = 0; i < steps; i++) {
 x += x_inc;
 y += y_inc;
 printf("(%.0f, %.0f)\n", round(x), round(y));
 }
}

int main() {
 DDA(2, 3, 10, 11);
 return 0;
}
